// Parse AI Response to JSON - für alle Items
const results = [];

for (const item of $input.all()) {
  const aiResponse = item.json.message?.content || 
                     item.json.text || 
                     item.json.content ||
                     item.json.candidates?.[0]?.content?.parts?.[0]?.text ||
                     '';

  let ownerData = {
    inhaber_name: null,
    inhaber_vorname: null,
    inhaber_nachname: null,
    inhaber_position: null,
    firma_name: null,
    generelle_email: null,
    confidence: 'low'
  };

  try {
    // Try to extract JSON from response
    const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      ownerData = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    console.log('JSON Parse Error:', e.message);
  }

  // Merge: Vorherige Daten vom selben Item + neue Owner-Daten
  results.push({
    json: {
      ...item.json,
      ...ownerData
    },
    pairedItem: item.pairedItem
  });
}

return results;

