// Für alle Items durchlaufen (wichtig für Item-Pairing!)
const results = [];

for (const item of $input.all()) {
  const htmlContent = item.json.data || 
                      item.json.body || 
                      item.json.html || 
                      '';

  function htmlToText(html) {
    if (!html || typeof html !== 'string') return '';

    let text = html
      .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
      .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '')
      .replace(/<noscript\b[^<]*(?:(?!<\/noscript>)<[^<]*)*<\/noscript>/gi, '')
      .replace(/<head\b[^<]*(?:(?!<\/head>)<[^<]*)*<\/head>/gi, '')
      .replace(/<nav\b[^<]*(?:(?!<\/nav>)<[^<]*)*<\/nav>/gi, '')
      .replace(/<footer\b[^<]*(?:(?!<\/footer>)<[^<]*)*<\/footer>/gi, '')
      .replace(/<!--[\s\S]*?-->/g, '')
      .replace(/<\/(p|div|h[1-6]|li|tr|br|hr)[^>]*>/gi, '\n')
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<hr\s*\/?>/gi, '\n---\n')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&ouml;/g, 'ö')
      .replace(/&auml;/g, 'ä')
      .replace(/&uuml;/g, 'ü')
      .replace(/&Ouml;/g, 'Ö')
      .replace(/&Auml;/g, 'Ä')
      .replace(/&Uuml;/g, 'Ü')
      .replace(/&szlig;/g, 'ß')
      .replace(/&#(\d+);/g, (match, dec) => String.fromCharCode(dec))
      .replace(/[ \t]+/g, ' ')
      .replace(/\n\s*\n/g, '\n\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();

    return text;
  }

  const cleanText = htmlToText(htmlContent);
  let impressumText = cleanText;

  const impressumPatterns = [
    /Impressum[\s\S]*?(?=Datenschutz|Privacy|Cookie|$)/i,
    /Angaben gemäß[\s\S]*?(?=Datenschutz|Privacy|Cookie|$)/i,
    /Verantwortlich[\s\S]*?(?=Datenschutz|Privacy|Cookie|$)/i
  ];

  for (const pattern of impressumPatterns) {
    const match = cleanText.match(pattern);
    if (match && match[0].length > 100) {
      impressumText = match[0];
      break;
    }
  }

  if (impressumText.length > 4000) {
    impressumText = impressumText.substring(0, 4000) + '...';
  }

  // Item mit allen vorherigen Daten + neuen Daten zurückgeben
  results.push({
    json: {
      ...item.json,
      impressumText: impressumText,
      impressumLength: impressumText.length,
      cleanupSuccess: impressumText.length > 50
    },
    pairedItem: item.pairedItem  // Wichtig für Item-Pairing!
  });
}

return results;

// Parse AI Response - korrigiert für verschachtelte Struktur
const results = [];

for (const item of $input.all()) {
  // Versuche verschiedene Pfade zur AI-Response
  let ownerData = null;

  // Pfad 1: OpenAI/Gemini Responses API Format
  if (item.json.output?.[0]?.content?.[0]?.text) {
    ownerData = item.json.output[0].content[0].text;
  }
  // Pfad 2: Direktes JSON in text
  else if (item.json.output?.[0]?.content?.[0]?.text && typeof item.json.output[0].content[0].text === 'string') {
    try {
      const jsonMatch = item.json.output[0].content[0].text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        ownerData = JSON.parse(jsonMatch[0]);
      }
    } catch (e) {}
  }
  // Pfad 3: Anthropic Format
  else if (item.json.content?.[0]?.text) {
    try {
      const jsonMatch = item.json.content[0].text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        ownerData = JSON.parse(jsonMatch[0]);
      }
    } catch (e) {}
  }
  // Pfad 4: Direktes message.content
  else if (item.json.message?.content) {
    try {
      const jsonMatch = item.json.message.content.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        ownerData = JSON.parse(jsonMatch[0]);
      }
    } catch (e) {}
  }

  // Fallback wenn nichts gefunden
  if (!ownerData) {
    ownerData = {
      inhaber_name: null,
      inhaber_vorname: null,
      inhaber_nachname: null,
      inhaber_position: null,
      firma_name: null,
      generelle_email: null,
      confidence: 'low'
    };
  }

  // Alle vorherigen Lead-Daten behalten (außer output)
  const { output, ...previousData } = item.json;

  results.push({
    json: {
      ...previousData,
      ...ownerData
    },
    pairedItem: item.pairedItem
  });
}

return results;

