// Findymail E-Mail Lookup mit Fallback auf generelle E-Mail
const results = [];

const FINDYMAIL_API_KEY ='API_KEY_HERE';

for (const item of $input.all()) {
  const vorname = item.json.inhaber_vorname;
  const nachname = item.json.inhaber_nachname;
  const generelleEmail = item.json.generelle_email;
  let website = item.json.website || '';

  // Domain extrahieren - erst von Website, sonst von genereller E-Mail
  let domain = '';

  if (website) {
    domain = website
      .replace('https://', '')
      .replace('http://', '')
      .replace('www.', '')
      .split('/')[0];
  } else if (generelleEmail && generelleEmail.includes('@')) {
    // Domain aus E-Mail extrahieren (z.B. user@example.com → firma.de)
    domain = generelleEmail.split('@')[1];
  }

  let emailResult = {
    email: null,
    emailConfidence: null,
    emailSource: null,
    emailError: null
  };

  // Nur API aufrufen wenn alle Daten vorhanden
  if (vorname && nachname && domain) {
    try {
      const response = await fetch('https://app.findymail.com/api/search/name', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${FINDYMAIL_API_KEY}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          first_name: vorname,
          last_name: nachname,
          domain: domain
        })
      });

      const data = await response.json();

      if (data.email) {
        emailResult.email = data.email;
        emailResult.emailConfidence = data.confidence || 'high';
        emailResult.emailSource = 'findymail';
      } else if (data.contact?.email) {
        emailResult.email = data.contact.email;
        emailResult.emailConfidence = data.contact.confidence || 'high';
        emailResult.emailSource = 'findymail';
      } else {
        // Kein Ergebnis - Fallback auf generelle E-Mail
        emailResult.emailError = data.error || 'No email found';
      }

    } catch (error) {
      emailResult.emailError = error.message;
    }
  } else {
    emailResult.emailError = `Missing: ${!vorname ? 'vorname ' : ''}${!nachname ? 'nachname ' : ''}${!domain ? 'domain' : ''}`;
  }

  // Fallback: Wenn keine E-Mail gefunden, nutze generelle E-Mail
  if (!emailResult.email && generelleEmail) {
    emailResult.email = generelleEmail;
    emailResult.emailConfidence = 'low';
    emailResult.emailSource = 'impressum_fallback';
  }

  results.push({
    json: {
      ...item.json,
      domain: domain,
      ...emailResult
    },
    pairedItem: item.pairedItem
  });
}

return results;
